    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xECED349C89D38B9DULL + 0xD1822A360F230015ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseC(pNonce * 0xD1A61E79FADCBF43ULL + 0x90B06D82D401045BULL);
