            aOrbiterE = (aOrbiterE ^ aOrbiterB) ^ 15908873150953195581U;
            aOrbiterE = RotL64((aOrbiterE * 18049755517524334107U), 35U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterK) + 11204775359756474667U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 2525984309543939465U;
            aOrbiterJ = RotL64((aOrbiterJ * 3988529812023791571U), 37U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterF) + 4566345170476825512U) + aNonceWordH;
            aOrbiterB = (aOrbiterB ^ aOrbiterC) ^ 14876612901557406267U;
            aOrbiterB = RotL64((aOrbiterB * 9047956948845135339U), 51U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterH) + 14926290877038883931U;
            aOrbiterG = (aOrbiterG ^ aOrbiterA) ^ 12710203178186614846U;
            aOrbiterG = RotL64((aOrbiterG * 14841163494801662515U), 13U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterB) + 7315094513967387996U;
            aOrbiterD = (aOrbiterD ^ aOrbiterK) ^ 11050116830482816766U;
            aOrbiterD = RotL64((aOrbiterD * 3702999495721152019U), 21U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterJ) + 4505368486032503953U) + aOrbiterUpdateSaltE[((aIndex + 22U)) & S_SALT1];
