            //
            aWandererG = aWandererG + ((RotL64(aPrevious, 41U) + aOrbiterE) + RotL64(aOrbiterJ, 13U));
            aWandererK = aWandererK ^ ((((RotL64(aCross, 37U) + RotL64(aOrbiterD, 57U)) + aOrbiterE) + aNonceWordN) + aWandererUpdateSaltE[((aIndex + 6U)) & S_SALT1]);
            aWandererC = aWandererC + ((RotL64(aIngress, 53U) + RotL64(aOrbiterK, 19U)) + aOrbiterI);
