            aOrbiterG = (aOrbiterG + aOrbiterE) + 3276844534476430842U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterG) ^ 6828644383891274120U) ^ aOrbiterUpdateSaltB[((aIndex + 29U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 979580351653410157U), 57U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterA) + 2815676923011504251U;
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 5030251870850928417U;
            aOrbiterI = RotL64((aOrbiterI * 7075653570570819253U), 13U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterH) + 13464083008377887034U) + aOrbiterUpdateSaltF[((aIndex + 16U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 8994560761846897590U;
            aOrbiterJ = RotL64((aOrbiterJ * 9892839554658865143U), 43U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 8398813387154468736U;
            aOrbiterE = (aOrbiterE ^ aOrbiterK) ^ 8136429428340910892U;
            aOrbiterE = RotL64((aOrbiterE * 3348811490733577295U), 37U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterK) + 418587250696862341U) + aNonceWordI;
            aOrbiterG = ((aOrbiterG ^ aOrbiterC) ^ 4111667833838312094U) ^ aNonceWordP;
