            aOrbiterK = (((aOrbiterK ^ aOrbiterB) ^ 2208124955874142264U) ^ aOrbiterUpdateSaltE[(((31U - aIndex) + 3U)) & S_SALT1]) ^ aNonceWordO;
            aOrbiterK = RotL64((aOrbiterK * 15741988616251072075U), 29U);
